interface OperatorMap {
  _id: string;
  satminkal: string;
  latitude?: string;
  longitude?: string;
  linkGoogleMaps?: string;
}

const PKG_CENTER: [number, number] = [-7.5624231, 111.4550711];

function FitMapBounds({ positions }: { positions: [number, number][] }) {
  const map = useMap();
  useEffect(() => {
    if (positions.length === 0) return;
    if (positions.length === 1) {
      map.setView(positions[0], 15);
      return;
    }
    const bounds = L.latLngBounds(positions);
    map.fitBounds(bounds, { padding: [40, 40], maxZoom: 15 });
  }, [map, positions]);
  return null;
}

function MapWithBounds({ operatorsForMap }: { operatorsForMap: OperatorMap[] }) {
  const allPositions = useMemo((): [number, number][] => {
    const opWithCoords = operatorsForMap.filter((op) => {
      const lat = parseFloat(op.latitude || '');
      const lng = parseFloat(op.longitude || '');
      return !Number.isNaN(lat) && !Number.isNaN(lng);
    });
    const opPositions = opWithCoords.map(
      (op) => [parseFloat(op.latitude!), parseFloat(op.longitude!)] as [number, number]
    );
    return [PKG_CENTER, ...opPositions];
  }, [operatorsForMap]);

  return (
    <MapContainer
      id="map-container"
      center={PKG_CENTER}
      zoom={15}
      className="h-full w-full z-0 pointer-events-none"
    >
      <TileLayer
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        attribution="PKG Barat - Pusat Kegiatan Guru Kecamatan Barat"
      />
      <FitMapBounds positions={allPositions} />
      <Marker position={PKG_CENTER} icon={pkgIcon}>
        <Popup>
          <b>PKG (Pusat Kegiatan Guru)</b>
          <br />
          Kecamatan Barat
          <br />
          <a
            href="https://maps.app.goo.gl/XhmyZn8y6xvPnSQP6"
            target="_blank"
            rel="noopener noreferrer"
            className="text-blue-600 hover:underline"
          >
            Buka di Google Maps
          </a>
        </Popup>
      </Marker>
      {operatorsForMap
        .filter((op) => {
          const lat = parseFloat(op.latitude || '');
          const lng = parseFloat(op.longitude || '');
          return !Number.isNaN(lat) && !Number.isNaN(lng);
        })
        .map((op) => (
          <Marker
            key={op._id}
            position={[parseFloat(op.latitude!), parseFloat(op.longitude!)]}
            icon={satminkalIcon}
          >
            <Popup>
              <b>{op.satminkal}</b>
              <br />
              {op.linkGoogleMaps ? (
                <a
                  href={op.linkGoogleMaps}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-600 hover:underline"
                >
                  Buka di Google Maps
                </a>
              ) : (
                'SATMINKAL'
              )}
            </Popup>
          </Marker>
        ))}
    </MapContainer>
  );
}

